def retry_call(fn, max_attempts=3):
    for attempt in range(1, max_attempts + 1):
        try:
            return ("ok", fn(attempt))
        except TimeoutError:
            if attempt == max_attempts:
                return ("fail_timeout", None)
        except ValueError as e:
            return ("quarantine", str(e))
    return ("fail", None)
    for attempt in range(1, max_attempts + 1):
        try:
            return ("ok", fn(attempt))
        except TimeoutError:
            if attempt == max_attempts:
                return ("fail_timeout", None)
        except ValueError as e:
            return ("quarantine", str(e))
    return ("fail", None)

